dmgFloat(x,y,dmg,head,isBoss){
  const showDmg=dmg>=1?Math.round(dmg):(Math.round(dmg*10)/10);
  const tier = isBoss?'boss':(head?'crit':(dmg>=5?'heavy':'light'));
  const STYLE={
    light:{size:'18px',color:'#fff0d4',stroke:'#1a0d0c',sw:2,prefix:'',dx:rnd(-20,20)},
    heavy:{size:'24px',color:'#ffd88a',stroke:'#3a1a0a',sw:3,prefix:'',dx:rnd(-26,26)},
    crit:{size:'34px',color:'#fff4cc',stroke:'#a01e1e',sw:4,prefix:'◉ ',dx:rnd(-12,12)},
    boss:{size:'28px',color:'#ff8c52',stroke:'#3a0a0a',sw:4,prefix:'◆ ',dx:rnd(-18,18)}
  }[tier];
  const t=this.add.text(x,y,STYLE.prefix+'-'+showDmg,{fontFamily:'"Black Ops One"',fontSize:STYLE.size,color:STYLE.color,stroke:STYLE.stroke,strokeThickness:STYLE.sw}).setOrigin(0.5).setDepth(86).setScale(0.3);
  this.tweens.add({targets:t,scale:tier==='crit'?1.2:(tier==='boss'?1.05:0.9),duration:140,ease:'Back.easeOut'});
  this.tweens.add({targets:t,x:x+STYLE.dx,y:y-rnd(70,95),angle:rnd(-8,8),alpha:0,duration:tier==='crit'?900:680,ease:'Cubic.easeOut',onComplete:()=>t.destroy()});
  if(tier==='crit'){
    const lbl=this.add.text(x+rnd(60,90),y-rnd(20,40),'HEADSHOT',{fontFamily:'"Oswald"',fontSize:'11px',color:'#ffd24a',fontStyle:'600'}).setOrigin(0.5).setDepth(86).setAlpha(0);
    lbl.setLetterSpacing && lbl.setLetterSpacing(3);
    this.tweens.add({targets:lbl,alpha:1,y:lbl.y-12,duration:160});
    this.tweens.add({targets:lbl,alpha:0,duration:500,delay:400,onComplete:()=>lbl.destroy()});
  }
}
